#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

using ll = long long;
using pii = pair<ll, int>;  // (ĶĘØń”╗, ĶŖéńé╣)

const ll INF = 1e18;

vector<ll> dijkstra(int start, const vector<vector<pii>>& g)
{
    int n = g.size();
    vector<ll> dist(n, INF);
    dist[start] = 0;
    
    // µ£ĆÕ░ÅÕĀå’╝īµīēĶĘØń”╗µÄÆÕ║Å
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.emplace(0, start);
    
    while (!pq.empty())
    {
        pair<ll, int> top = pq.top();
        ll d = top.first;
        int u = top.second;
        pq.pop();
        
        if (d > dist[u])
        {
            continue;  // µŚ¦ńÜäĶĘ»ÕŠä’╝īĶĘ│Ķ┐ć
        }
        
        for (const auto& edge : g[u])
        {
            int v = edge.first;
            ll w = edge.second;
            if (dist[v] > dist[u] + w)
            {
                dist[v] = dist[u] + w;
                pq.emplace(dist[v], v);
            }
        }
    }
    
    return dist;
}

signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m, start;
    cin >> n >> m >> start;
    
    vector<vector<pii>> g(n);
    for (int i = 0; i < m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        g[u].emplace_back(v, w);
    }
    
    vector<ll> dist = dijkstra(start, g);
    for (int i = 0; i < n; i++)
    {
        if (dist[i] == INF)
        {
            cout << "INF ";
        }
        else
        {
            cout << dist[i] << " ";
        }
    }
    
    return 0;
}
```

### 3.2 Ķ┤¬Õ┐āń«Śµ│Ģ

