            CustomError::ParseError => write!(f, "Ķ¦Żµ×ÉķöÖĶ»»"),
        }
    }
}

impl std::error::Error for CustomError {}

// õĮ┐ńö©Ķć¬Õ«Üõ╣ēķöÖĶ»»
fn risky_operation(success: bool) -> Result<(), CustomError>
{
    if success
